import Avatar from "../UI/Avatar";
import classes from "./UserPanel.module.css";

const UserPanel = (props) => {
  return (
    <section>
      <Avatar
        image={"https://animedao.to/images/call-of-the-night.jpg"}
        size={32}
      ></Avatar>
      <div>
        <div>Eric</div>
        <div>Test</div>
      </div>
  
    </section>
  );
};

export default UserPanel;
